// Rate limiting logic: send first error immediately, suppress duplicates, batch at window end
const item = $input.first();
const staticData = this.getWorkflowStaticData('global');

// Extract basic error info
const workflowName = item.json.workflow?.name || 'Unknown Workflow';
const workflowId = item.json.workflow?.id || 'unknown';
const failedNode = item.json.execution?.lastNodeExecuted || 'Unknown Node';

// Create a unique key for this workflow+node combination
const errorKey = `${workflowId}_${failedNode}`;
const now = Date.now();
const rateLimitWindow = 5 * 60 * 1000; // 5 minutes
const maxStoredErrors = 50; // Cap stored errors to prevent unbounded growth

// Initialize error tracking structure
if (!staticData.errorTracking) {
  staticData.errorTracking = {};
}

// Prune stale keys older than 2x the window
for (const key of Object.keys(staticData.errorTracking)) {
  if (now - staticData.errorTracking[key].firstSeen > rateLimitWindow * 2) {
    delete staticData.errorTracking[key];
  }
}

// Get or create tracking entry for this error key
if (!staticData.errorTracking[errorKey]) {
  staticData.errorTracking[errorKey] = {
    count: 0,
    firstSeen: now,
    lastSent: 0,
    errors: []
  };
}

const tracking = staticData.errorTracking[errorKey];

// Check if we're outside the rate limit window - send batch summary then reset
if (now - tracking.firstSeen > rateLimitWindow) {
  // Window expired: if there were suppressed errors, send a batch summary
  if (tracking.count > 1) {
    const batchErrors = tracking.errors.slice(-10);
    const batchCount = tracking.count;
    // Reset tracking for new window
    tracking.count = 1;
    tracking.firstSeen = now;
    tracking.lastSent = now;
    tracking.errors = [{
      executionId: item.json.execution?.id || 'unknown',
      errorMessage: item.json.execution?.error?.message || 'No error message',
      timestamp: now
    }];
    return {
      ...item.json,
      rateLimiting: {
        shouldSend: true,
        emailType: 'batch',
        errorCount: batchCount,
        errorKey: errorKey,
        errors: batchErrors
      }
    };
  }
  // Window expired with no suppressed errors, reset and treat as first
  tracking.count = 0;
  tracking.firstSeen = now;
  tracking.errors = [];
}

// Add this error to the tracking (cap the array)
tracking.count++;
if (tracking.errors.length < maxStoredErrors) {
  tracking.errors.push({
    executionId: item.json.execution?.id || 'unknown',
    errorMessage: item.json.execution?.error?.message || 'No error message',
    timestamp: now
  });
}

// Determine if we should send email
let shouldSend = false;
let emailType = 'single';

if (tracking.count === 1) {
  // First error in window - always send immediately
  shouldSend = true;
  emailType = 'single';
  tracking.lastSent = now;
} else {
  // Subsequent errors within window - suppress (will be batched when window expires)
  shouldSend = false;
}

// Pass through the original data plus rate limit info
return {
  ...item.json,
  rateLimiting: {
    shouldSend: shouldSend,
    emailType: emailType,
    errorCount: tracking.count,
    errorKey: errorKey,
    errors: tracking.errors
  }
};

